package jetbrains.mps.baseLanguage.pluginSolution.plugin;

/*Generated by MPS */

import jetbrains.mps.checkers.IChecker;
import jetbrains.mps.errors.item.IssueKindReportItem;
import org.jetbrains.mps.openapi.module.SModule;
import org.jetbrains.mps.openapi.module.SRepository;
import org.jetbrains.mps.openapi.util.Consumer;
import org.jetbrains.mps.openapi.util.ProgressMonitor;
import jetbrains.mps.project.Project;
import jetbrains.mps.project.SModuleOperations;
import jetbrains.mps.project.facets.JavaModuleFacet;
import jetbrains.mps.project.facets.JavaLanguageLevel;
import jetbrains.mps.compiler.JavaCompilerOptionsComponent;
import jetbrains.mps.errors.item.ModuleReportItemBase;
import org.jetbrains.mps.openapi.module.SModuleReference;
import jetbrains.mps.errors.MessageStatus;

public class JavaTargetVersionCheck extends IChecker.AbstractModuleChecker<IssueKindReportItem> {

  @Override
  public void check(SModule toCheck, SRepository repository, Consumer<? super IssueKindReportItem> errorCollector, ProgressMonitor monitor) {
    // indeed, ProjectHelper.getProject(repository) is viable alternative, just wanted to keep the reference to the method in SModuleOperations.
    // XXX I believe we shall rather pass MPS Project here (reasonable for any user-induced activity) or take one from a full-fledged project repository (once
    //    its story is complete. Now it is a ProjectRepository, yet I want to have this odd SModuleOperations method here as a reminder to get back here and fix this place)
    //    Alternative approach is to have per-project checker instance (can register one from project, not app part), yet still need a way to figure out where the module originates from.
    Project project = SModuleOperations.getProjectForModule(toCheck);
    JavaModuleFacet jmf = toCheck.getFacet(JavaModuleFacet.class);
    if (project == null || jmf == null || jmf.getCompile() == JavaModuleFacet.Compile.None) {
      return;
    }

    final JavaLanguageLevel srcLevel = jmf.getLanguageLevel();
    // FIXME I believe using CompilerSettingsComponent directly is better approach here. After all, this is workbench-level extension, and got no troubles
    //      accessing IDEA code.
    final JavaCompilerOptionsComponent.JavaVersion targetLevel = JavaCompilerOptionsComponent.getInstance().getJavaCompilerOptions(project).getTargetJavaVersion();
    final JavaCompilerOptionsComponent.JavaVersion atLeast;
    switch (srcLevel) {
      case JAVA_7:
        atLeast = JavaCompilerOptionsComponent.JavaVersion.VERSION_1_7;
        break;
      case JAVA_8:
      case JAVA_8_NO_LAMBDA:
        atLeast = JavaCompilerOptionsComponent.JavaVersion.VERSION_1_8;
        break;
      case JAVA_9:
        atLeast = JavaCompilerOptionsComponent.JavaVersion.VERSION_9;
        break;
      case JAVA_10:
        atLeast = JavaCompilerOptionsComponent.JavaVersion.VERSION_10;
        break;
      default:
        throw new IllegalStateException(String.format("Unexpected value for Java source level for module %s: %s", toCheck.getModuleName(), srcLevel));
    }
    if (targetLevel.isAtLeast(atLeast)) {
      return;
    }
    IssueKindReportItem mismatch = new VersionMismatch(toCheck.getModuleReference(), targetLevel, atLeast);
    errorCollector.accept(mismatch);
  }

  @Override
  public IssueKindReportItem.CheckerCategory getCategory() {
    // this checker aims to augment original non-typechecking rules ('default' methods and 'super' call in interfaces), therefore stick to category of NonTypesystemChecker)
    return IssueKindReportItem.TYPESYSTEM;
  }

  private static class VersionMismatch extends ModuleReportItemBase {
    private VersionMismatch(SModuleReference mref, JavaCompilerOptionsComponent.JavaVersion target, JavaCompilerOptionsComponent.JavaVersion sources) {
      super(MessageStatus.ERROR, mref, String.format("Module's Java source level is %s, while project targets Java version %s", target, sources));
    }

    @Override
    public IssueKindReportItem.ItemKind getIssueKind() {
      // XXX I know this creates new ItemKind instance, I don't care - after all, it's just once per module.
      return IssueKindReportItem.TYPESYSTEM.deriveItemKind("error");
    }
  }
}
